name = #{name}, no = #{no}, gender = #{gender}, phone = #{phone}, id_card = #{idCard}, is_college = #{isCollege}, address = #{address}, graduation_date = #{graduationDate}, clazz_id = #{clazzId}, degree = #{degree}, violation_count = #{violationCount}, violation_score = #{violationScore}, update_time = #{updateTime}
where id = #{id}

update student

    violation_count = violation_count + 1,
    violation_score = violation_score + #{score},
    update_time = #{updateTime}

where id = #{id}

